insert into youth_candidates (name, kana, email, type, school, grade, status, source, applied_at, motivation, interview2_dates, interview3_dates) values
  ('大西雄大', 'おおにしたけひろ', 'takkekyupy@gmail.com', '大学生・専門学生・大学院生', '九州大学', '農学部 1年生', '応募完了', null, '2026-03-10', '僕は将来、環境ビジネスで世界を動かすリーダーになると決めています。しかし、現時点では「根拠のない自信」しか持ち合わせておらず、理想と実力の乖離に強い危機感を抱いています。', '候補日①：2026/03/30(月) 19:00~21:00, 候補日②：2026/04/01(水) 19:00~21:00', '上記の日程で調整可能'),
